import{_ as a,o as s,c as t,ai as n}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Remote Access","description":"","frontmatter":{"summary":"Remote access using SSH tunnels (Gateway WS) and tailnets","read_when":["Running or troubleshooting remote gateway setups"],"title":"Remote Access"},"headers":[],"relativePath":"gateway/remote.md","filePath":"gateway/remote.md","lastUpdated":1771906665000}'),o={name:"gateway/remote.md"};function i(l,e,r,h,p,c){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="remote-access-ssh-tunnels-and-tailnets" tabindex="-1"><a class="header-anchor" href="#remote-access-ssh-tunnels-and-tailnets">#</a> Remote access (SSH, tunnels, and tailnets)</h1><p>This repo supports “remote over SSH” by keeping a single Gateway (the master) running on a dedicated host (desktop/server) and connecting clients to it.</p><ul><li>For <strong>operators (you / the macOS app)</strong>: SSH tunneling is the universal fallback.</li><li>For <strong>nodes (iOS/Android and future devices)</strong>: connect to the Gateway <strong>WebSocket</strong> (LAN/tailnet or SSH tunnel as needed).</li></ul><h2 id="the-core-idea" tabindex="-1"><a class="header-anchor" href="#the-core-idea">#</a> The core idea</h2><ul><li>The Gateway WebSocket binds to <strong>loopback</strong> on your configured port (defaults to 18789).</li><li>For remote use, you forward that loopback port over SSH (or use a tailnet/VPN and tunnel less).</li></ul><h2 id="common-vpn-tailnet-setups-where-the-agent-lives" tabindex="-1"><a class="header-anchor" href="#common-vpn-tailnet-setups-where-the-agent-lives">#</a> Common VPN/tailnet setups (where the agent lives)</h2><p>Think of the <strong>Gateway host</strong> as “where the agent lives.” It owns sessions, auth profiles, channels, and state. Your laptop/desktop (and nodes) connect to that host.</p><h3 id="_1-always-on-gateway-in-your-tailnet-vps-or-home-server" tabindex="-1"><a class="header-anchor" href="#_1-always-on-gateway-in-your-tailnet-vps-or-home-server">#</a> 1) Always-on Gateway in your tailnet (VPS or home server)</h3><p>Run the Gateway on a persistent host and reach it via <strong>Tailscale</strong> or SSH.</p><ul><li><strong>Best UX:</strong> keep <code>gateway.bind: &quot;loopback&quot;</code> and use <strong>Tailscale Serve</strong> for the Control UI.</li><li><strong>Fallback:</strong> keep loopback + SSH tunnel from any machine that needs access.</li><li><strong>Examples:</strong> <a href="/docs/install/exe-dev">exe.dev</a> (easy VM) or <a href="/docs/install/hetzner">Hetzner</a> (production VPS).</li></ul><p>This is ideal when your laptop sleeps often but you want the agent always-on.</p><h3 id="_2-home-desktop-runs-the-gateway-laptop-is-remote-control" tabindex="-1"><a class="header-anchor" href="#_2-home-desktop-runs-the-gateway-laptop-is-remote-control">#</a> 2) Home desktop runs the Gateway, laptop is remote control</h3><p>The laptop does <strong>not</strong> run the agent. It connects remotely:</p><ul><li>Use the macOS app’s <strong>Remote over SSH</strong> mode (Settings → General → “OpenSoul runs”).</li><li>The app opens and manages the tunnel, so WebChat + health checks “just work.”</li></ul><p>Runbook: <a href="/docs/platforms/mac/remote">macOS remote access</a>.</p><h3 id="_3-laptop-runs-the-gateway-remote-access-from-other-machines" tabindex="-1"><a class="header-anchor" href="#_3-laptop-runs-the-gateway-remote-access-from-other-machines">#</a> 3) Laptop runs the Gateway, remote access from other machines</h3><p>Keep the Gateway local but expose it safely:</p><ul><li>SSH tunnel to the laptop from other machines, or</li><li>Tailscale Serve the Control UI and keep the Gateway loopback-only.</li></ul><p>Guide: <a href="/docs/gateway/tailscale">Tailscale</a> and <a href="/docs/web/index">Web overview</a>.</p><h2 id="command-flow-what-runs-where" tabindex="-1"><a class="header-anchor" href="#command-flow-what-runs-where">#</a> Command flow (what runs where)</h2><p>One gateway service owns state + channels. Nodes are peripherals.</p><p>Flow example (Telegram → node):</p><ul><li>Telegram message arrives at the <strong>Gateway</strong>.</li><li>Gateway runs the <strong>agent</strong> and decides whether to call a node tool.</li><li>Gateway calls the <strong>node</strong> over the Gateway WebSocket (<code>node.*</code> RPC).</li><li>Node returns the result; Gateway replies back out to Telegram.</li></ul><p>Notes:</p><ul><li><strong>Nodes do not run the gateway service.</strong> Only one gateway should run per host unless you intentionally run isolated profiles (see <a href="/docs/gateway/multiple-gateways">Multiple gateways</a>).</li><li>macOS app “node mode” is just a node client over the Gateway WebSocket.</li></ul><h2 id="ssh-tunnel-cli-tools" tabindex="-1"><a class="header-anchor" href="#ssh-tunnel-cli-tools">#</a> SSH tunnel (CLI + tools)</h2><p>Create a local tunnel to the remote Gateway WS:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 18789:127.0.0.1:18789</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@host</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>With the tunnel up:</p><ul><li><code>opensoul health</code> and <code>opensoul status --deep</code> now reach the remote gateway via <code>ws://127.0.0.1:18789</code>.</li><li><code>opensoul gateway {status,health,send,agent,call}</code> can also target the forwarded URL via <code>--url</code> when needed.</li></ul><p>Note: replace <code>18789</code> with your configured <code>gateway.port</code> (or <code>--port</code>/<code>OPENSOUL_GATEWAY_PORT</code>). Note: when you pass <code>--url</code>, the CLI does not fall back to config or environment credentials. Include <code>--token</code> or <code>--password</code> explicitly. Missing explicit credentials is an error.</p><h2 id="cli-remote-defaults" tabindex="-1"><a class="header-anchor" href="#cli-remote-defaults">#</a> CLI remote defaults</h2><p>You can persist a remote target so CLI commands use it by default:</p><div class="language-json5 vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  gateway</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    mode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;remote&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    remote</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      url</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ws://127.0.0.1:18789&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      token</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;your-token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>When the gateway is loopback-only, keep the URL at <code>ws://127.0.0.1:18789</code> and open the SSH tunnel first.</p><h2 id="chat-ui-over-ssh" tabindex="-1"><a class="header-anchor" href="#chat-ui-over-ssh">#</a> Chat UI over SSH</h2><p>WebChat no longer uses a separate HTTP port. The SwiftUI chat UI connects directly to the Gateway WebSocket.</p><ul><li>Forward <code>18789</code> over SSH (see above), then connect clients to <code>ws://127.0.0.1:18789</code>.</li><li>On macOS, prefer the app’s “Remote over SSH” mode, which manages the tunnel automatically.</li></ul><h2 id="macos-app-remote-over-ssh" tabindex="-1"><a class="header-anchor" href="#macos-app-remote-over-ssh">#</a> macOS app “Remote over SSH”</h2><p>The macOS menu bar app can drive the same setup end-to-end (remote status checks, WebChat, and Voice Wake forwarding).</p><p>Runbook: <a href="/docs/platforms/mac/remote">macOS remote access</a>.</p><h2 id="security-rules-remote-vpn" tabindex="-1"><a class="header-anchor" href="#security-rules-remote-vpn">#</a> Security rules (remote/VPN)</h2><p>Short version: <strong>keep the Gateway loopback-only</strong> unless you’re sure you need a bind.</p><ul><li><strong>Loopback + SSH/Tailscale Serve</strong> is the safest default (no public exposure).</li><li><strong>Non-loopback binds</strong> (<code>lan</code>/<code>tailnet</code>/<code>custom</code>, or <code>auto</code> when loopback is unavailable) must use auth tokens/passwords.</li><li><code>gateway.remote.token</code> is <strong>only</strong> for remote CLI calls — it does <strong>not</strong> enable local auth.</li><li><code>gateway.remote.tlsFingerprint</code> pins the remote TLS cert when using <code>wss://</code>.</li><li><strong>Tailscale Serve</strong> can authenticate via identity headers when <code>gateway.auth.allowTailscale: true</code>. Set it to <code>false</code> if you want tokens/passwords instead.</li><li>Treat browser control like operator access: tailnet-only + deliberate node pairing.</li></ul><p>Deep dive: <a href="/docs/gateway/security/index">Security</a>.</p>`,45)])])}const g=a(o,[["render",i]]);export{u as __pageData,g as default};
